import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.C7qU-Vik.js";const u=JSON.parse('{"title":"Function: updateAdaptiveWeights()","description":"","frontmatter":{},"headers":[],"relativePath":"api/functions/updateAdaptiveWeights.md","filePath":"api/functions/updateAdaptiveWeights.md"}'),i={name:"api/functions/updateAdaptiveWeights.md"};function n(d,e,s,p,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<p><a href="./../README"><strong>monad.ai</strong></a></p><hr><p><a href="./../README">monad.ai</a> / updateAdaptiveWeights</p><h1 id="function-updateadaptiveweights" tabindex="-1">Function: updateAdaptiveWeights() <a class="header-anchor" href="#function-updateadaptiveweights" aria-label="Permalink to &quot;Function: updateAdaptiveWeights()&quot;">​</a></h1><blockquote><p><strong>updateAdaptiveWeights</strong>(<code>reward</code>, <code>breakdown</code>, <code>optionsOrLearningRate?</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/neurons-me/monad/blob/f6d0fb6d4d7c8661ca9f05a2c1b6bad00e861f5e/npm/src/kernel/adaptiveWeights.ts#L366" target="_blank" rel="noreferrer">kernel/adaptiveWeights.ts:366</a></p><p>Applies one online gradient step to the globally learned weights.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δweight = learningRate × reward × contribution</span></span></code></pre></div><p>Scorers with high contribution to a good outcome get heavier; scorers that pushed a bad decision get lighter. The update is idempotent with respect to sign: a series of failures will keep driving a weight toward <code>WEIGHT_MIN</code> but can never push it below that floor.</p><p>NaN and zero rewards are ignored (no-ops).</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><h3 id="reward" tabindex="-1">reward <a class="header-anchor" href="#reward" aria-label="Permalink to &quot;reward&quot;">​</a></h3><p><code>number</code></p><p>Continuous reward signal in [−1, 1]; from <a href="./correlateOutcome">correlateOutcome</a>.</p><h3 id="breakdown" tabindex="-1">breakdown <a class="header-anchor" href="#breakdown" aria-label="Permalink to &quot;breakdown&quot;">​</a></h3><p><code>Record</code>&lt;<code>string</code>, <a href="./../type-aliases/ScorerBreakdown"><code>ScorerBreakdown</code></a>&gt;</p><p>Per-scorer contributions from the decision being evaluated.</p><h3 id="optionsorlearningrate" tabindex="-1">optionsOrLearningRate? <a class="header-anchor" href="#optionsorlearningrate" aria-label="Permalink to &quot;optionsOrLearningRate?&quot;">​</a></h3><p><code>number</code> | <a href="./../type-aliases/AdaptiveWeightUpdateOptions"><code>AdaptiveWeightUpdateOptions</code></a></p><p>Either a legacy numeric learning rate, or an options object with <code>namespace</code> and/or <code>learningRate</code>.</p><h2 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h2><p><code>void</code></p>',22)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
